import{_ as a,o as l,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"钠离子电池 2026 量产进展：良率、成本与规模出货","description":"","frontmatter":{"updated":"2026-06-23T00:00:00.000Z","visibility":"public"},"headers":[],"relativePath":"电力新能源/储能/_深化_2026-06-16_钠电成本与良率.md","filePath":"电力新能源/储能/_深化_2026-06-16_钠电成本与良率.md","lastUpdated":1782226922000}'),d={name:"电力新能源/储能/_深化_2026-06-16_钠电成本与良率.md"};function e(o,t,h,n,s,u){return l(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="钠离子电池-2026-量产进展-良率、成本与规模出货" tabindex="-1">钠离子电池 2026 量产进展：良率、成本与规模出货 <a class="header-anchor" href="#钠离子电池-2026-量产进展-良率、成本与规模出货" aria-label="Permalink to &quot;钠离子电池 2026 量产进展：良率、成本与规模出货&quot;">​</a></h1><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>2026年上半年，钠离子电池产业迎来历史性拐点：宁德时代签下 3 年 60GWh 全球最大钠电池订单，众钠能源全球首个万吨级正极材料基地投产，多家企业良率追平锂电。电芯制造成本已降至 0.35-0.40 元/Wh，部分领先企业压降至 0.3 元/Wh，年内有望追平磷酸铁锂。2026 年全球钠电出货量预计突破 6GWh，2027 年飙升至 15GWh。</p><h2 id="量产进展" tabindex="-1">量产进展 <a class="header-anchor" href="#量产进展" aria-label="Permalink to &quot;量产进展&quot;">​</a></h2><h3 id="宁德时代-行业龙头" tabindex="-1">宁德时代：行业龙头 <a class="header-anchor" href="#宁德时代-行业龙头" aria-label="Permalink to &quot;宁德时代：行业龙头&quot;">​</a></h3><ul><li>2026 年 4 月超级科技日宣布&quot;钠新&quot;电池将于 Q4 正式规模化量产</li><li>攻克钠离子电池量产四大行业难题（材料残碱度高、极片水分、负极产气、一致性控制）</li><li>与海博思创签署 3 年 60GWh 战略协议——迄今全球最大钠电池订单</li><li>福鼎建成专用钠离子电池产线，9 月首批储能系统交付，全年 GWh 级出货</li><li>第二代&quot;钠新&quot;量产电池能量密度 175Wh/kg，与 LFP 差距缩至 10% 以内</li><li>常温循环寿命 15000 次，-20℃ 低温容量保持率超 90%，电芯产热较 LFP 降低 60%</li><li>采用与锂离子电池同尺寸平台化设计，与现有产业链高度兼容</li><li>预计钠电池未来将替代 30%-40% 现有电池市场份额（曾毓群）</li></ul><h3 id="众钠能源-聚阴离子路线先行者" tabindex="-1">众钠能源：聚阴离子路线先行者 <a class="header-anchor" href="#众钠能源-聚阴离子路线先行者" aria-label="Permalink to &quot;众钠能源：聚阴离子路线先行者&quot;">​</a></h3><ul><li>2026 年 1 月四川眉山万吨级硫酸铁钠正极基地投产——全球首个</li><li>硫酸铁钠钠电电芯成本已降至约 0.45 元/Wh</li><li>在手订单饱满，正极材料万吨产能已被锁定</li><li>电芯及两轮车询单同比翻倍</li><li>配套电芯中试产线同步建成，与成熟电芯厂合作推进 GWh 级量产</li></ul><h3 id="国轩高科-追赶者" tabindex="-1">国轩高科：追赶者 <a class="header-anchor" href="#国轩高科-追赶者" aria-label="Permalink to &quot;国轩高科：追赶者&quot;">​</a></h3><ul><li>宣布 2026 年 Q4 实现钠电池规模化量产</li><li>已攻克钠枝晶析出、热失控等安全难题</li><li>钠电池顺利通过极限安全测试</li></ul><h3 id="容百科技-材料先行" tabindex="-1">容百科技：材料先行 <a class="header-anchor" href="#容百科技-材料先行" aria-label="Permalink to &quot;容百科技：材料先行&quot;">​</a></h3><ul><li>湖北仙桃 6000 吨聚阴离子正极材料产能，2026 年拓展至 2.8 万吨</li><li>2027 年计划新建 30 万吨钠电专用产线</li><li>本年度规模化量产的钠电正极材料成本已与碳酸锂 15 万元/吨场景下的 LFP 正极持平</li><li>NFPP 循环寿命超过 15000 次</li></ul><h2 id="成本分析" tabindex="-1">成本分析 <a class="header-anchor" href="#成本分析" aria-label="Permalink to &quot;成本分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时间节点</th><th>钠电电芯成本 (元/Wh)</th><th>LFP 电芯成本 (元/Wh)</th><th>价差</th></tr></thead><tbody><tr><td>2026 Q1</td><td>0.35-0.40</td><td>0.36-0.38</td><td>&lt;0.1</td></tr><tr><td>2026 年中 (领先企业)</td><td>0.30</td><td>0.36-0.40 (锂价上涨后)</td><td>追平</td></tr><tr><td>2026 年底 (预期)</td><td>0.35-0.40</td><td>0.38-0.42 (锂价 20 万/吨)</td><td>打平</td></tr><tr><td>2030 (预测)</td><td>0.25</td><td>0.30-0.35</td><td>优势明显</td></tr></tbody></table><p>成本下降驱动因素：</p><ol><li><strong>规模化量产</strong>：GWh 级产线释放规模降本红利</li><li><strong>良率提升</strong>：良品率已追平锂电</li><li><strong>硬碳负极国产化</strong>：预计从 6-7 万元/吨降至 3.5-4 万元/吨（2026 年）</li><li><strong>产线兼容</strong>：与锂电产线设备高度兼容，降低适配成本</li><li><strong>材料端竞争</strong>：容百/珈钠/恩捷等材料龙头加速扩产</li></ol><h2 id="技术路线对比" tabindex="-1">技术路线对比 <a class="header-anchor" href="#技术路线对比" aria-label="Permalink to &quot;技术路线对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>技术路线</th><th>代表企业</th><th>优势</th><th>劣势</th></tr></thead><tbody><tr><td>层状氧化物</td><td>宁德时代</td><td>能量密度高（175Wh/kg），动力场景适配</td><td>循环寿命略逊</td></tr><tr><td>聚阴离子 (硫酸铁钠)</td><td>众钠能源/容百科技</td><td>循环寿命长（&gt;15000 次），储能场景适配</td><td>能量密度较低</td></tr><tr><td>普鲁士白</td><td>少量企业</td><td>成本最低</td><td>结晶水控制困难，一致性差</td></tr></tbody></table><h2 id="竞争格局" tabindex="-1">竞争格局 <a class="header-anchor" href="#竞争格局" aria-label="Permalink to &quot;竞争格局&quot;">​</a></h2><ul><li><strong>产能集中度</strong>：头部企业加速扩产，成熟万吨级生产线仍稀缺</li><li><strong>材料瓶颈</strong>：多数材料仅维持千吨级产能，硬碳负极是最大瓶颈</li><li><strong>行业标准</strong>：2026 年 2 月《储能用钠离子电池技术要求》正式实施，进入&quot;有标可依&quot;阶段</li><li><strong>工信部调研</strong>：2026 年 6 月组织钠电产业调研会（宁德时代/容百/海博思创/万华化学），释放提速信号</li><li><strong>出货量预测</strong>：SMM 预测 2026 年全球钠电出货量突破 6GWh，2027 年飙升至 15GWh</li></ul><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><ol><li><strong>材料短缺</strong>：硬碳负极国产化不及预期，成熟万吨级产线稀缺</li><li><strong>锂价波动</strong>：若碳酸锂价格大幅下跌，钠电经济性窗口收窄</li><li><strong>产能过剩</strong>：2027 年可能进入过剩高峰</li><li><strong>技术路线不确定性</strong>：层状氧化物 vs 聚阴离子路线尚未定论</li><li><strong>替代天花板</strong>：钠电能量密度硬伤，无法替代高端动力电池场景</li></ol><hr><p><em>来源：经济观察网、财联社、SMM、中国银河证券研报、中信建投研报</em><em>更新：2026-06-16</em></p>',24)])])}const b=a(d,[["render",e]]);export{c as __pageData,b as default};
